            IsPublished = true,
            SortOrder = 6,
            AppRoutes = """["/admin/edi"]""",
            Tags = """["edi","admin","import","reference"]""",
            ContentJson = """{"title":"Part-Number Map CSV Import","groups":[{"heading":"Where to import","items":[{"label":"Open the map","value":"Admin > EDI > Trading Partners tab > the partner row's ⇄ (swap_horiz) Part-Number Map action."},{"label":"Import CSV button","value":"In the dialog toolbar, next to Add Row. Opens a file picker (.csv or .txt)."},{"label":"Per-partner","value":"The import targets the one partner whose map is open. Each partner has its own map."}]},{"heading":"File format","items":[{"label":"Two columns","value":"Column 1 = the partner's part number. Column 2 = your (our) part number."},{"label":"Header row required","value":"The first row must be a header. A file with only data rows (no header) imports nothing."},{"label":"Encoding","value":"Plain CSV. Quoted fields and escaped double-quotes (\"\") inside quotes are supported."},{"label":"Blank lines","value":"Fully blank rows are ignored."}]},{"heading":"Accepted column headers","items":[{"label":"Partner column","value":"A header containing any of: 'partner', 'their', or 'customer' (case-insensitive). E.g. 'Partner Part #', 'Their Number', 'Customer Item'."},{"label":"Our column","value":"A header containing any of: 'our', 'forge', or 'internal'. E.g. 'Our Part #', 'Internal Number'."},{"label":"Positional fallback","value":"If the headers aren't recognized, the import falls back to position: column 1 = partner, column 2 = ours. (A header row is still required.)"}]},{"heading":"How rows merge (upsert)","items":[{"label":"Upsert by partner number","value":"A partner number already in the map is UPDATED with the new 'our' number; a partner number not yet present is ADDED. Re-importing a corrected file does not create duplicates."},{"label":"Trimming","value":"Leading/trailing spaces are trimmed from both numbers."},{"label":"Case-insensitive keys","value":"Partner numbers match case-insensitively, so 'ABC' and 'abc' are treated as the same key (last one wins)."},{"label":"Empty cells skipped","value":"A row missing either number is skipped (counted in Skipped)."}]},{"heading":"Result counts (shown after import)","items":[{"label":"Imported","value":"Rows added as new partner-number entries."},{"label":"Updated","value":"Existing partner-number entries whose 'our' number was changed."},{"label":"Skipped","value":"Rows skipped because a number cell was blank."},{"label":"Unresolved","value":"After merging, how many map rows point at a part number that matches no catalog part — a data-quality signal to fix before orders flow."},{"label":"Total Rows","value":"Total rows in the map after the import completes."}]},{"heading":"Example file","items":[{"label":"Header","value":"PartnerPartNumber,OurPartNumber"},{"label":"Row 1","value":"AC-1000,WIDGET-001"},{"label":"Row 2","value":"AC-1001,WIDGET-002"},{"label":"Result","value":"Two new pairs added; if WIDGET-002 isn't in your catalog yet, Unresolved = 1 and that row shows a 'No matching part' chip in the grid."}]}]}"""
        });

        // ── EDI — Advanced Reference (Reference) ─────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "EDI — Advanced Reference",
            Slug = "edi-reference",
            Summary = "Edge-case and power-user reference for EDI: qualifier ID codes, partner→Customer/Vendor linking, control numbers, transport deep dive, and why UOM/pack-qty translation isn't built.",
            ContentType = TrainingContentType.Reference,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 90,
            AppRoutes = """["/admin/edi"]""",
            Tags = """["edi","reference","advanced"]""",
            ContentJson = """{"body":"## EDI — Advanced Reference\n\nPower-user and edge-case notes for the EDI module (Admin > EDI). This is reference material, not a tutorial — see the core EDI modules for the day-to-day workflow. Everything here is factual to the shipped data model.\n\n## Qualifier ID Code Reference\n\nThe **Qualifier ID** field on a trading partner is the EDI interchange ID qualifier — a short code (max 10 chars) that tells the receiver how to interpret the partner's **Qualifier Value**. It is not the partner's identity; it is the *type* of the identity. The pairing (Qualifier ID + Qualifier Value) uniquely addresses the partner in the interchange envelope (the X12 ISA05/ISA06 and ISA07/ISA08 elements).\n\nCommon values:\n\n- **01** — DUNS (Dun & Bradstreet 9-digit).\n- **08** — UCC/EAN (GS1) Global Location Number.\n- **12** — Phone number used as the identifier.\n- **14** — DUNS+4 (DUNS plus a 4-digit suffix for a sub-location).\n- **ZZ** — Mutually Defined. Both parties agree on the value's meaning out-of-band. This is the QB Engineer default because most small/mid trading relationships negotiate a code rather than use a registry ID.\n\nLess common but valid codes you may see in a partner's spec: **02** (SCAC), **04** (IATA), **09** (X.121), **20** (HIN), **30** (US Federal Tax ID / EIN). Note that **AS2** is a transport, not a qualifier — do not confuse the two. Store whatever code the partner's EDI implementation guide dictates; QB Engineer does not validate the value against a registry — it round-trips the code verbatim.\n\n## Partner → Customer / Vendor Linking\n\nA trading partner is an EDI addressing record; a Customer or Vendor is a business entity. Linking the two lets QB Engineer resolve an inbound document to the right account automatically.\n\n- The partner carries two independent, nullable links: **CustomerId** and **VendorId**. A partner can be linked to a Customer (the typical case for inbound 850 purchase orders), to a Vendor (for documents you receive as a buyer), or to neither.\n- The link drives **entity matching** during processing: when an inbound 850 is applied, the resulting Sales Order is created against the linked Customer. Without a link, the document still parses but has no account to attach to, so it stalls for manual resolution.\n- The link is **not** the same as the EDI envelope IDs. A partner separately stores **InterchangeSenderId / InterchangeReceiverId** and **ApplicationSenderId / ApplicationReceiverId** — the routing identifiers in the ISA and GS segments. Those address the *mailbox*; the Customer/Vendor link addresses the *account*.\n- A single business can hold one Customer link and one Vendor link on the same partner record if you both sell to and buy from them under one EDI relationship — but the two FKs are stored independently, not as a single polymorphic reference.\n\n## Control Numbers\n\nEvery EDI transaction tracks three nested control numbers mirroring the X12 envelope hierarchy. They are stored on the transaction (not the partner) and surfaced in the transaction detail dialog.\n\n- **ControlNumber** (interchange control number) — the ISA13 value. Uniquely identifies the whole interchange envelope between two partners. This is the value shown as 'Control #' in the transactions list.\n- **GroupControlNumber** — the GS06 value. Identifies a functional group within the interchange (a batch of like documents).\n- **TransactionControlNumber** — the ST02 value. Identifies the individual transaction set inside the group.\n\nAll three are nullable strings — a transaction from a partner that omits a level, or a manually-uploaded document, may not populate every one. Functional acknowledgments (997/CONTRL) reference these numbers to tell the partner exactly which interchange/group/transaction is being acknowledged or rejected; the acknowledgment transaction links back via **AcknowledgmentTransactionId**.\n\n## Transport Deep Reference (AS2 / VAN / API)\n\nThe six transport methods (As2, Sftp, Van, Email, Api, Manual) are an enum on the partner. Beyond the one-line summaries in the core reference, the operationally meaningful distinctions:\n\n- **AS2** — Point-to-point over HTTP(S) with S/MIME encryption and signing. Its defining feature is the **MDN** (Message Disposition Notification) — a signed receipt the receiver returns, giving non-repudiation of delivery. No middleman; you exchange certificates and AS2 IDs/URLs directly with the partner. Best for high-volume, direct relationships.\n- **VAN** (Value Added Network) — A third-party mailbox service (SPS Commerce, TrueCommerce, Cleo, etc.) that sits between you and the partner. The VAN handles delivery, often format translation and compliance checking, and an interconnect to *other* VANs. You connect once to the VAN and reach many partners. Trades per-document cost for zero point-to-point setup.\n- **API** — Direct REST/SOAP integration with the partner's system, bypassing traditional EDI transport entirely. Large retailers and marketplaces increasingly expose this. The EDI *content* may still be X12/EDIFACT, or it may be the partner's own JSON contract that QB Engineer maps the same way.\n- **SFTP** — File drop in partner-specific directories on a secure server. QB Engineer writes outbound to one directory and polls another for inbound. Has its own credential fieldset (host, port default 22, username, password, inbound/outbound directories); the stored password is kept on edit unless retyped.\n- **Email** and **Manual** — low-automation fallbacks; Manual is the recommended starting point while validating an integration before cutting over to an automated transport.\n\nSwitching a partner's transport is just changing the enum value (and supplying the new transport's credentials) — it does not alter the partner's identity, links, or transaction history.\n\n## UOM / Pack-Quantity Translation (Not Built)\n\nThe per-partner **Part-Number Map** translates a partner's part number to yours — a pure *number swap*. It deliberately does **not** translate units of measure or pack quantities.\n\n- If a partner orders in cases and you stock in eaches, or the partner's 850 line carries a UOM code (EA, CA, BX, PL) different from your part's stocking unit, QB Engineer does **not** convert the quantity. The number flows through as-is against your part.\n- There is no UOM cross-reference table and no pack-quantity multiplier in the EDI module today. Treat any partner that requires this as a configuration/process conversation, not a self-service setup step.\n- Practical guardrail: for partners whose ordering UOM differs from your stocking UOM, review applied 850s before fulfillment, or agree with the partner to transact in your stocking unit. This is the most common source of quantity surprises on inbound orders, and is documented here precisely because the UI gives no knob for it.\n","sections":[]}"""
        });

        Log.Information("Seeded EDI training modules");
    }
